sys_script_include.script:
var Constants = Class.create();

Constants.APP_SCOPE = 'x_dice_digicertone';

Constants.SYS_PROPS = {
	save_to_cmdb: Constants.APP_SCOPE + '.save_to_cmdb',
	production_mode: Constants.APP_SCOPE + '.production_mode',
	use_mid_server: Constants.APP_SCOPE + '.use_mid_server',
};

Constants.ROLE = {
    ANY: '*',
    ADMIN: 'admin',
    BUSINESS_OWNER: Constants.APP_SCOPE + '.business_owner',
    SUBSCRIBER: Constants.APP_SCOPE + '.subscriber',
    USER: Constants.APP_SCOPE + '.user',
};

Constants.EVENT = {
    pickUpCertificate: Constants.APP_SCOPE + '.pickUpCertificate',
    requestRejected: Constants.APP_SCOPE + '.request.rejected',
    certificateGenerated: Constants.APP_SCOPE + '.certificate.generated',
	certificateFailed: Constants.APP_SCOPE + '.certificate.failed',
	certificateDelayed: Constants.APP_SCOPE + '.certificate.delayed',
	certificateFailedAdmin: Constants.APP_SCOPE + '.cert.failed.admin',
	syncCertificates: Constants.APP_SCOPE + '.sync_certificates',
	renewCertificate: Constants.APP_SCOPE + '.certificate.renewal',
};

Constants.URL = {
    getProfilesUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') +
        '/mpki/api/v2/profile?limit=' +
        (gs.getProperty(Constants.APP_SCOPE + '.profiles_limit_to_fetch') || 100),
    pickUpCertificateUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/certificate-pickup/{request_id}',
    issueCertificateUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/certificate',
    renewCertificateUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') +
        '/mpki/api/v1/certificate/{serialNumber}/renew?thumbprint_sha256={thumbprint}',
    revokeCertificateUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') +
        '/mpki/api/v1/certificate/{serialNumber}/revoke?thumbprint_sha256={thumbprint}',
    manualEnrollmentUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/manual-enrollment',
	manualRenewalUrl:gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/manual-enrollment/renew/{old_cert_id}',
    enrollmentStatusUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/enrollment/{enrollment_id}/status',
    getCertificateDetailsBySerialNumberUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/certificate/{serialNumber}',
    getCertificateDetailsByEnrollmentId: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') +
        '/mpki/api/v1/certificate-search?enrollment_id={enrollmentId}',
    validateAPITokenUrl: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/hello',
	getUser: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/account/api/v1/user/me',
	getCertificatesMigrationStatus: gs.getProperty(Constants.APP_SCOPE + '.base_api_url') + '/mpki/api/v1/service-now/{accountId}/status',
};

Constants.DC_ONE_AUTH_HEADER = 'x-api-key';

Constants.APPLICATION_SECURITY_PROPERTY = {
    table: Constants.APP_SCOPE + '_application_secure_properties',
    digicertOneApiKey: 'digicert_one_api_key',
};

Constants.PROFILE = {
    table: Constants.APP_SCOPE + '_profiles',
    statuses: {
        Active: 'Active',
        Inactive: 'Inactive',
        Suspended: 'Suspended',
        Deleted: 'Deleted',
    },
};

Constants.CERTIFICATE_REQUEST = {
    table: Constants.APP_SCOPE + '_certificate_request',
};

Constants.SUPPORT_USER = {
    table: Constants.APP_SCOPE + '_support_user',
};

Constants.CERTIFICATE = {
    table: Constants.APP_SCOPE + '_certificates',
    statuses: {
        Issued: 'issued',
        Revoked: 'revoked',
        Expired: 'expired',
        Suspended: 'suspended',
		RevocationPending:'revocation_pending'
    },
};

Constants.APPLICATION_PROPERTIES = {
	table: Constants.APP_SCOPE + '_application_properties',
	props: {
		sync_certificates: {
			name: "sync_certificates",
			status: {
				processed: "processed",
				processing: "processing",
			}
		}
	}
};

// in seconds
Constants.REQUEST_TIME_OUT = 30;

Constants.ENROLLMENT_METHODS ={
	CSR:'csr'
};

Constants.AUTHENTICATION_METHODS ={
	MANUAL_APPROVAL:'manual_approval'
};

// set your MID server name here to be used in dev mode
Constants.MIDServerName = "my_mid_server";
